"use client";

import { useState, useCallback, useEffect, useRef } from "react";
import { Editor } from "@/components/editor/Editor";
import { useAutoSave } from "@/hooks/useAutoSave";
import { useSession } from "@/hooks/useSession";
import { SaveIndicator } from "@/components/editor/SaveIndicator";
import { BackLink } from "@/components/ui/BackLink";
import { Button } from "@/components/ui/button";
import Link from "next/link";

const PANEL_STATE_VERSION = 1;

interface StoredPanelState {
  version: number;
  chatOpen: boolean;
  editorOpen: boolean;
}

function panelStateKey(documentId: string): string {
  return `provenance:editor:${documentId}:panels`;
}

function readPanelState(documentId: string): Pick<StoredPanelState, "chatOpen" | "editorOpen"> {
  if (typeof window === "undefined") {
    return { chatOpen: true, editorOpen: true };
  }

  try {
    const raw = window.localStorage.getItem(panelStateKey(documentId));
    if (!raw) return { chatOpen: true, editorOpen: true };
    const parsed = JSON.parse(raw) as Partial<StoredPanelState>;
    if (parsed.version !== PANEL_STATE_VERSION) {
      return { chatOpen: true, editorOpen: true };
    }
    const chatOpen = parsed.chatOpen !== false;
    const editorOpen = parsed.editorOpen !== false;
    if (!chatOpen && !editorOpen) {
      return { chatOpen: true, editorOpen: true };
    }
    return { chatOpen, editorOpen };
  } catch {
    return { chatOpen: true, editorOpen: true };
  }
}

interface ThreadSummary {
  id: string;
  title: string;
  messageCount: number | null;
  updatedAt: Date | null;
}

interface EditorShellProps {
  documentId: string;
  initialTitle: string;
  initialContent: Record<string, unknown>;
  aiProvider: string;
  aiModel: string | null;
  latestBadgeVerificationId?: string | null;
  initialChatThreads?: ThreadSummary[];
}

export function EditorShell({
  documentId,
  initialTitle,
  initialContent,
  aiProvider,
  aiModel,
  latestBadgeVerificationId,
  initialChatThreads = [],
}: EditorShellProps) {
  const [title, setTitle] = useState(initialTitle);
  const [chatOpen, setChatOpen] = useState(
    () => readPanelState(documentId).chatOpen
  );
  const [editorOpen, setEditorOpen] = useState(
    () => readPanelState(documentId).editorOpen
  );
  const { save, status, retry, isDirty } = useAutoSave({ documentId, title });
  const { markActive } = useSession({ documentId });
  const isDirtyRef = useRef(isDirty);

  isDirtyRef.current = isDirty;

  const handleUpdate = useCallback(
    (json: Record<string, unknown>) => {
      markActive();
      save(json);
    },
    [save, markActive]
  );

  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (!isDirtyRef.current) return;

      const anchor = (e.target as HTMLElement).closest("a");
      if (!anchor) return;

      const href = anchor.getAttribute("href");
      if (!href || href.startsWith("http") || href.startsWith("#")) return;

      const confirmed = window.confirm(
        "You have unsaved changes. Are you sure you want to leave?"
      );

      if (!confirmed) {
        e.preventDefault();
        e.stopPropagation();
      }
    };

    document.addEventListener("click", handleClick, true);
    return () => document.removeEventListener("click", handleClick, true);
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(
      panelStateKey(documentId),
      JSON.stringify({
        version: PANEL_STATE_VERSION,
        chatOpen,
        editorOpen,
      } satisfies StoredPanelState)
    );
  }, [documentId, chatOpen, editorOpen]);

  return (
    <div className="flex min-h-0 flex-1 flex-col">
      <a href="#editor-content" className="sr-only focus:not-sr-only focus:absolute focus:z-50 focus:rounded-md focus:bg-background focus:px-3 focus:py-2 focus:text-sm focus:shadow-md">
        Skip to editor
      </a>
      <nav className="flex shrink-0 items-center gap-3 border-b border-border px-2 py-1.5" aria-label="Editor navigation">
        <BackLink href="/dashboard" />
        <input
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          aria-label="Document title"
          data-testid="document-title"
          className="flex-1 rounded-md bg-transparent px-1 text-lg font-semibold outline-none placeholder:text-muted-foreground focus-visible:ring-2 focus-visible:ring-ring/50"
          placeholder="Untitled"
        />
        <SaveIndicator status={status} onRetry={retry} />
        {latestBadgeVerificationId && (
          <Button variant="outline" size="sm" asChild>
            <Link href={`/verify/${latestBadgeVerificationId}`}>
              View Badge
            </Link>
          </Button>
        )}
        <Button variant="outline" size="sm" asChild>
          <Link href={`/editor/${documentId}/preview`} data-testid="generate-badge">
            Generate Badge
          </Link>
        </Button>
      </nav>
      <Editor
        content={initialContent}
        documentId={documentId}
        provider={aiProvider}
        model={aiModel ?? undefined}
        onUpdate={handleUpdate}
        chatOpen={chatOpen}
        onChatToggle={() => {
          if (!chatOpen || editorOpen) setChatOpen((v) => !v);
        }}
        editorOpen={editorOpen}
        onEditorToggle={() => {
          if (!editorOpen || chatOpen) setEditorOpen((v) => !v);
        }}
        initialChatThreads={initialChatThreads}
      />
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import Link from "next/link";
import { Trash2 } from "lucide-react";

interface DocumentRowProps {
  id: string;
  title: string;
  updatedAt: string | Date | null;
  wordCount: number | null;
  preview?: string;
  aiPercentage?: number | null;
  hasBadge: boolean;
  latestBadgeVerificationId?: string | null;
  isArchived?: boolean;
  onClick?: () => void;
  onDelete?: (id: string) => void;
}

function getAIBadgeColor(percentage: number): string {
  if (percentage <= 25) return "bg-emerald-50 text-emerald-700";
  if (percentage <= 50) return "bg-amber-50 text-amber-700";
  if (percentage <= 75) return "bg-orange-50 text-orange-700";
  return "bg-red-50 text-red-700";
}

function relativeDate(date: string | Date | null): string {
  if (!date) return "";
  const d = new Date(date);
  const now = new Date();
  const diffMs = now.getTime() - d.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMs / 3600000);
  const diffDays = Math.floor(diffMs / 86400000);

  if (diffMins < 1) return "just now";
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays < 7) return `${diffDays}d ago`;
  return d.toLocaleDateString();
}

export function DocumentRow({
  id,
  title,
  updatedAt,
  wordCount,
  preview,
  aiPercentage,
  hasBadge,
  latestBadgeVerificationId,
  isArchived,
  onClick,
  onDelete,
}: DocumentRowProps) {
  return (
    <div
      onClick={onClick}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") onClick?.(); }}
      className={cn(
        "flex w-full items-start gap-3 border-b border-border px-4 py-3 text-left hover:bg-muted cursor-pointer transition-colors duration-150",
        isArchived && "opacity-60"
      )}
    >
      {/* Status dot */}
      <span
        className={cn(
          "mt-1.5 inline-block h-2.5 w-2.5 shrink-0 rounded-full",
          hasBadge ? "bg-emerald-500" : isArchived ? "bg-muted-foreground/30" : "bg-muted-foreground/50"
        )}
      />

      <div className="min-w-0 flex-1">
        <div className="flex items-center justify-between gap-2">
          <span className="truncate text-sm font-medium">{title || "Untitled"}</span>
          <div className="flex shrink-0 items-center gap-2">
            <span className="text-xs text-muted-foreground">
              {relativeDate(updatedAt)}
            </span>
            {onDelete && (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  onDelete(id);
                }}
                className="rounded p-1 text-muted-foreground hover:bg-red-50 hover:text-red-600 transition-colors duration-150"
                aria-label={`Delete ${title || "Untitled"}`}
              >
                <Trash2 className="h-3.5 w-3.5" />
              </button>
            )}
          </div>
        </div>

        {preview && (
          <p className="mt-0.5 truncate text-xs text-muted-foreground">{preview}</p>
        )}

        <div className="mt-1 flex items-center gap-2">
          {aiPercentage != null && (
            <span className={`rounded px-1.5 py-0.5 text-xs font-medium font-mono tabular-nums ${getAIBadgeColor(aiPercentage)}`}>
              {aiPercentage}% AI
            </span>
          )}
          {wordCount != null && (
            <span className="text-xs text-muted-foreground font-mono tabular-nums">
              {wordCount.toLocaleString()} words
            </span>
          )}
          {latestBadgeVerificationId && (
            <Link
              href={`/verify/${latestBadgeVerificationId}`}
              className="rounded px-1.5 py-0.5 text-xs font-medium text-provenance-700 hover:bg-provenance-50 hover:text-provenance-800"
              onClick={(e) => e.stopPropagation()}
            >
              View badge
            </Link>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { FileText, Clock, Archive, Trash2, Settings } from "lucide-react";
import { cn } from "@/lib/utils";

export type SidebarFilter = "all" | "recent" | "archive" | "trash";

const NAV_ITEMS = [
  { id: "all" as const, label: "All Documents", icon: FileText },
  { id: "recent" as const, label: "Recent", icon: Clock },
  { id: "archive" as const, label: "Archive", icon: Archive },
  { id: "trash" as const, label: "Trash", icon: Trash2 },
];

interface SidebarProps {
  activeFilter: SidebarFilter;
  onFilterChange: (filter: SidebarFilter) => void;
  onSettingsClick?: () => void;
}

export function Sidebar({ activeFilter, onFilterChange, onSettingsClick }: SidebarProps) {
  return (
    <div className="flex w-56 flex-col border-r border-border bg-muted/50 p-4" role="navigation" aria-label="Sidebar">
      <div className="mb-4 flex items-center gap-2 px-3">
        <span className="text-lg font-bold text-provenance-700">◆</span>
        <span className="text-sm font-semibold text-provenance-900">Provenance</span>
      </div>
      <nav className="flex flex-col gap-1" aria-label="Document filters">
        {NAV_ITEMS.map((item) => {
          const isActive = activeFilter === item.id;
          const Icon = item.icon;
          return (
            <button
              key={item.id}
              onClick={() => onFilterChange(item.id)}
              className={cn(
                "flex items-center gap-2 rounded-md px-3 py-2 text-sm transition-colors duration-150",
                isActive
                  ? "bg-provenance-50 font-medium text-provenance-700"
                  : "text-muted-foreground hover:bg-accent"
              )}
            >
              <Icon className="h-4 w-4" />
              {item.label}
            </button>
          );
        })}
      </nav>

      <div className="mt-auto">
        <button
          onClick={onSettingsClick}
          className="flex w-full items-center gap-2 rounded-md px-3 py-2 text-sm text-muted-foreground hover:bg-accent transition-colors duration-150"
        >
          <Settings className="h-4 w-4" />
          Settings
        </button>
      </div>
    </div>
  );
}

