"use client";

import { useRef, useCallback, useEffect } from "react";
import { ArrowUp, Square } from "lucide-react";
import { Button } from "@/components/ui/button";

interface ChatInputProps {
  value: string;
  onChange: (value: string) => void;
  onSubmit: () => void;
  onStop?: () => void;
  isStreaming: boolean;
  disabled?: boolean;
  wordCount?: number;
  hasMessages?: boolean;
}

export function ChatInput({
  value,
  onChange,
  onSubmit,
  onStop,
  isStreaming,
  disabled,
  wordCount,
  hasMessages,
}: ChatInputProps) {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const adjustHeight = useCallback(() => {
    const textarea = textareaRef.current;
    if (!textarea) return;
    textarea.style.height = "auto";
    const maxHeight = 6 * 24; // ~6 lines
    textarea.style.height = `${Math.min(textarea.scrollHeight, maxHeight)}px`;
  }, []);

  useEffect(() => {
    adjustHeight();
  }, [value, adjustHeight]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        if (!isStreaming && !disabled && value.trim()) {
          onSubmit();
        }
      }
    },
    [isStreaming, disabled, value, onSubmit]
  );

  return (
    <div className="border-t border-border px-4 py-3">
      {/* Context chip — only shown when document has content */}
      {wordCount != null && wordCount > 0 && (
        <div className="mb-2 inline-flex items-center gap-1.5 rounded border border-border bg-secondary px-2 py-0.5 text-xs font-medium text-muted-foreground">
          <span className="h-1.5 w-1.5 rounded-full bg-foreground/40" />
          {`Full document · ${wordCount!.toLocaleString()} words`}
        </div>
      )}

      {/* Input wrapper */}
      <div className="flex items-end gap-2 rounded-lg border border-border bg-white px-3 py-2 transition-colors focus-within:border-provenance-500 focus-within:shadow-[0_0_0_3px_rgba(76,110,245,0.08)]">
        <textarea
          ref={textareaRef}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Ask about your writing..."
          rows={1}
          disabled={disabled}
          className="flex-1 resize-none bg-transparent text-sm leading-snug text-foreground outline-none placeholder:text-muted-foreground disabled:opacity-50"
        />
        {isStreaming ? (
          <Button
            variant="provenance"
            size="icon-xs"
            onClick={onStop}
            aria-label="Stop generating"
          >
            <Square className="h-3 w-3" />
          </Button>
        ) : (
          <Button
            variant="provenance"
            size="icon-xs"
            onClick={onSubmit}
            disabled={disabled || !value.trim()}
            aria-label="Send message"
          >
            <ArrowUp className="h-3.5 w-3.5" />
          </Button>
        )}
      </div>

      {/* Keyboard hints — hidden once conversation starts */}
      {!hasMessages && (
        <div className="mt-1.5 flex gap-2 px-0.5 text-xs text-muted-foreground">
          <span>
            <kbd className="rounded border border-border bg-secondary px-1.5 py-0.5 text-xs font-medium text-muted-foreground">
              ⌘ L
            </kbd>{" "}
            toggle
          </span>
          <span>
            <kbd className="rounded border border-border bg-secondary px-1.5 py-0.5 text-xs font-medium text-muted-foreground">
              Enter
            </kbd>{" "}
            send
          </span>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useCallback, useRef, useEffect, useMemo } from "react";
import { useChat } from "@ai-sdk/react";
import { DefaultChatTransport } from "ai";
import type { UIMessage } from "ai";
import { ChatHeader } from "./ChatHeader";
import { ChatMessage } from "./ChatMessage";
import { ChatInput } from "./ChatInput";
import { ChatEmptyState } from "./ChatEmptyState";
import {
  getChatThread,
  saveChatThread,
} from "@/app/actions/chat-threads";

interface ThreadSummary {
  id: string;
  title: string;
  messageCount: number | null;
  updatedAt: Date | null;
}

interface ChatPanelProps {
  documentId: string;
  provider: string;
  model?: string;
  getDocumentContent: () => Record<string, unknown>;
  initialThreads: ThreadSummary[];
  onAssistantResponse?: (responseText: string) => void;
  onClose: () => void;
}

function extractPlainTextFromContent(
  content: Record<string, unknown>
): string {
  const extract = (node: Record<string, unknown>): string => {
    if (node.text && typeof node.text === "string") return node.text;
    if (Array.isArray(node.content)) {
      return node.content.map((child) => extract(child)).join("");
    }
    return "";
  };
  return extract(content);
}

function getTextFromMessage(message: UIMessage): string {
  return message.parts
    .filter((p): p is { type: "text"; text: string } => p.type === "text")
    .map((p) => p.text)
    .join("");
}

export function ChatPanel({
  documentId,
  provider,
  model,
  getDocumentContent,
  initialThreads,
  onAssistantResponse,
  onClose,
}: ChatPanelProps) {
  const [threads, setThreads] = useState<ThreadSummary[]>(initialThreads);
  const [activeThreadId, setActiveThreadId] = useState<string | null>(null);
  const [selectedProvider, setSelectedProvider] = useState(provider);
  const [selectedModel, setSelectedModel] = useState(model);
  const [inputValue, setInputValue] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const startTimeRef = useRef<number>(0);
  const streamThreadIdRef = useRef<string | null>(null);
  const savingRef = useRef(false);

  const getDocumentContext = useCallback(
    () => extractPlainTextFromContent(getDocumentContent()),
    [getDocumentContent]
  );

  const wordCount = useMemo(
    () => getDocumentContext().split(/\s+/).filter(Boolean).length,
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [getDocumentContent]
  );

  const handleModelChange = useCallback(
    (newProvider: string, newModel: string) => {
      setSelectedProvider(newProvider);
      setSelectedModel(newModel);
    },
    []
  );

  const transportRef = useRef({ getDocumentContext, activeThreadId, selectedProvider, selectedModel });
  transportRef.current = { getDocumentContext, activeThreadId, selectedProvider, selectedModel };

  const transport = useMemo(
    () =>
      new DefaultChatTransport({
        api: "/api/chat",
        prepareSendMessagesRequest: ({ messages: msgs, id }) => ({
          body: {
            id,
            messages: msgs,
            documentContext: transportRef.current.getDocumentContext(),
            ...(transportRef.current.activeThreadId
              ? { threadId: transportRef.current.activeThreadId }
              : {}),
            provider: transportRef.current.selectedProvider,
            model: transportRef.current.selectedModel,
          },
        }),
      }),
    []
  );

  const {
    messages,
    setMessages,
    sendMessage,
    status,
    stop,
  } = useChat({
    transport,
    experimental_throttle: 50,
    onFinish: async ({ message, messages: allMessages }) => {
      const threadId = streamThreadIdRef.current;
      const assistantText = getTextFromMessage(message).trim();
      if (assistantText) {
        onAssistantResponse?.(assistantText);
      }

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const metadata = message.metadata as Record<string, any> | undefined;
      const elapsed = Math.round((Date.now() - startTimeRef.current) / 60000);

      const firstUserMsg = allMessages.find((m) => m.role === "user");
      const title = firstUserMsg
        ? getTextFromMessage(firstUserMsg).slice(0, 50) || "New conversation"
        : "New conversation";

      if (!threadId && savingRef.current) return;
      savingRef.current = true;

      try {
        const saved = await saveChatThread({
          documentId,
          threadId: threadId ?? undefined,
          title,
          messages: allMessages,
          messageCount: allMessages.length,
          summary: {
            messageCount: allMessages.length,
            durationMinutes: elapsed,
            category: "ask",
            provider: metadata?.provider ?? selectedProvider,
            model: metadata?.model ?? selectedModel ?? "",
            ...(metadata?.tokenCount
              ? { tokenCount: metadata.tokenCount }
              : {}),
          },
        });

        if (!threadId && saved) {
          setActiveThreadId(saved.id);
          streamThreadIdRef.current = saved.id;
          setThreads((prev) => [
            {
              id: saved.id,
              title: saved.title,
              messageCount: saved.messageCount,
              updatedAt: saved.updatedAt,
            },
            ...prev,
          ]);
        } else if (saved) {
          setThreads((prev) =>
            prev.map((t) =>
              t.id === saved.id
                ? {
                    ...t,
                    title: saved.title,
                    messageCount: saved.messageCount,
                    updatedAt: saved.updatedAt,
                  }
                : t
            )
          );
        }
      } catch (err) {
        console.error("[ChatPanel] Failed to save thread:", err);
      } finally {
        savingRef.current = false;
      }
    },
  });

  const isStreaming = status === "streaming";

  useEffect(() => {
    if (initialThreads.length === 0) {
      if (!startTimeRef.current) startTimeRef.current = Date.now();
      return;
    }

    let cancelled = false;
    const latestThreadId = initialThreads[0]?.id;
    if (!latestThreadId) return;

    void (async () => {
      try {
        const thread = await getChatThread(latestThreadId);
        if (cancelled) return;
        setActiveThreadId(thread.id);
        streamThreadIdRef.current = thread.id;
        setMessages((thread.messages ?? []) as UIMessage[]);
        startTimeRef.current = Date.now();
      } catch (err) {
        if (!cancelled) {
          console.error("[ChatPanel] Failed to restore latest thread:", err);
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [initialThreads, setMessages]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleThreadSelect = useCallback(
    async (threadId: string | null) => {
      if (isStreaming) stop();

      if (!threadId) {
        setActiveThreadId(null);
        streamThreadIdRef.current = null;
        setMessages([]);
        startTimeRef.current = Date.now();
        return;
      }

      try {
        const thread = await getChatThread(threadId);
        setActiveThreadId(thread.id);
        streamThreadIdRef.current = thread.id;
        setMessages((thread.messages ?? []) as UIMessage[]);
        startTimeRef.current = Date.now();
      } catch (err) {
        console.error("[ChatPanel] Failed to load thread:", err);
      }
    },
    [setMessages, isStreaming, stop]
  );

  const handleNewThread = useCallback(() => {
    if (isStreaming) stop();
    setActiveThreadId(null);
    streamThreadIdRef.current = null;
    setMessages([]);
    setInputValue("");
    startTimeRef.current = Date.now();
  }, [setMessages, isStreaming, stop]);

  const handleSubmit = useCallback(() => {
    if (!inputValue.trim()) return;
    const text = inputValue;
    setInputValue("");
    streamThreadIdRef.current = activeThreadId;
    startTimeRef.current = startTimeRef.current || Date.now();
    sendMessage({ text });
  }, [inputValue, sendMessage, activeThreadId]);

  const handleSuggestionClick = useCallback(
    (suggestion: string) => {
      setInputValue("");
      streamThreadIdRef.current = activeThreadId;
      startTimeRef.current = Date.now();
      sendMessage({ text: suggestion });
    },
    [sendMessage, activeThreadId]
  );

  return (
    <div className="flex h-full flex-col bg-muted">
      <ChatHeader
        threads={threads}
        activeThreadId={activeThreadId}
        onThreadSelect={handleThreadSelect}
        onNewThread={handleNewThread}
        onClose={onClose}
        selectedProvider={selectedProvider}
        selectedModel={selectedModel}
        onModelChange={handleModelChange}
      />

      <div className="flex-1 overflow-y-auto px-4 py-5">
        {messages.length === 0 ? (
          <ChatEmptyState onSuggestionClick={handleSuggestionClick} />
        ) : (
          <div className="flex flex-col gap-4">
            {messages.map((message, i) => (
              <ChatMessage
                key={message.id ?? i}
                message={message}
                isStreaming={
                  isStreaming && i === messages.length - 1 && message.role === "assistant"
                }
              />
            ))}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      <ChatInput
        value={inputValue}
        onChange={setInputValue}
        onSubmit={handleSubmit}
        onStop={stop}
        isStreaming={isStreaming}
        wordCount={wordCount}
        hasMessages={messages.length > 0}
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import {
  groupEventsByDay,
  clusterRevisions,
  getEventCounts,
  type DayGroup,
  type TimelineEvent,
  type RevisionCluster,
} from "@/lib/timeline-utils";
import { Play } from "lucide-react";
import { TimelineMinimap } from "./TimelineMinimap";

interface AuditTimelineProps {
  interactions: Array<{
    mode: string;
    prompt: string;
    response: string;
    action: string;
    createdAt: string | Date | null;
  }>;
  pasteEvents: Array<{
    sourceType: string;
    characterCount: number;
    createdAt: string | Date | null;
  }>;
  sessions: Array<{
    startedAt: string | Date | null;
    endedAt: string | Date | null;
    activeSeconds: number | null;
  }>;
  revisions: Array<{
    trigger: string;
    createdAt: string | Date | null;
  }>;
  showBadgeLandmark?: boolean;
}

type FilterType = "all" | "ai_interaction" | "paste" | "revision";

function formatTime(ts: string | Date | null): string {
  if (!ts) return "";
  const d = new Date(ts);
  return d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
}

export function AuditTimeline(props: AuditTimelineProps) {
  const [activeFilter, setActiveFilter] = useState<FilterType>("all");
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set());

  // Build raw events
  const rawEvents = [
    ...props.interactions.map((i) => ({
      type: "ai_interaction" as const,
      timestamp: i.createdAt,
      data: i as Record<string, unknown>,
    })),
    ...props.pasteEvents.map((p) => ({
      type: "paste" as const,
      timestamp: p.createdAt,
      data: p as Record<string, unknown>,
    })),
    ...props.sessions.flatMap((s) => {
      const events: Array<{ type: "session_start" | "session_end"; timestamp: string | Date | null; data: Record<string, unknown> }> = [
        { type: "session_start", timestamp: s.startedAt, data: s as Record<string, unknown> },
      ];
      if (s.endedAt) {
        events.push({ type: "session_end", timestamp: s.endedAt, data: s as Record<string, unknown> });
      }
      return events;
    }),
    ...props.revisions.map((r) => ({
      type: "revision" as const,
      timestamp: r.createdAt,
      data: r as Record<string, unknown>,
    })),
  ];

  rawEvents.sort((a, b) => {
    const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
    const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
    return ta - tb;
  });

  const counts = getEventCounts(rawEvents);
  const days = groupEventsByDay(rawEvents);

  if (rawEvents.length === 0) {
    return (
      <div className="rounded-lg border p-4 text-center text-sm text-muted-foreground">
        No audit events recorded.
      </div>
    );
  }

  const filterChips: { id: FilterType; label: string; count: number; dotColor: string }[] = [
    { id: "all", label: "All", count: counts.ai_interaction + counts.paste + counts.revision, dotColor: "bg-muted-foreground" },
    { id: "ai_interaction", label: "AI", count: counts.ai_interaction, dotColor: "bg-violet-400" },
    { id: "paste", label: "Paste", count: counts.paste, dotColor: "bg-orange-400" },
    { id: "revision", label: "Revisions", count: counts.revision, dotColor: "bg-muted-foreground/50" },
  ];

  return (
    <div data-testid="audit-timeline">
      {/* Minimap */}
      <div className="mb-4">
        <TimelineMinimap
          interactions={props.interactions}
          pasteEvents={props.pasteEvents}
          sessions={props.sessions}
        />
      </div>

      {/* Filter chips */}
      <div className="mb-4 flex flex-wrap gap-2" data-testid="filter-chips">
        {filterChips.map((chip) => (
          <button
            key={chip.id}
            onClick={() => setActiveFilter(chip.id)}
            className={`flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium transition-colors duration-150 ${
              activeFilter === chip.id
                ? "bg-secondary text-foreground"
                : "bg-secondary/50 text-muted-foreground hover:bg-secondary"
            }`}
          >
            <span className={`inline-block h-2 w-2 rounded-full ${chip.dotColor}`} />
            {chip.label}
            <span className="font-mono tabular-nums text-muted-foreground">({chip.count})</span>
          </button>
        ))}
      </div>

      {/* Timeline */}
      <div className="space-y-6">
        {days.map((day) => (
          <DaySection
            key={day.date}
            day={day}
            activeFilter={activeFilter}
            expandedKeys={expandedKeys}
            onToggleExpand={(key) =>
              setExpandedKeys((prev) => {
                const next = new Set(prev);
                if (next.has(key)) next.delete(key);
                else next.add(key);
                return next;
              })
            }
          />
        ))}
      </div>

      {/* Badge landmark — only shown on verification pages */}
      {props.showBadgeLandmark !== false && (
        <div className="mt-6 rounded-lg border border-emerald-200 bg-emerald-50/50 p-4 text-center" data-testid="badge-landmark">
          <div className="text-sm font-medium text-emerald-700">
            Badge Generated
          </div>
          <div className="text-xs text-emerald-600">
            Audit trail frozen at this point
          </div>
        </div>
      )}
    </div>
  );
}

function DaySection({
  day,
  activeFilter,
  expandedKeys,
  onToggleExpand,
}: {
  day: DayGroup;
  activeFilter: FilterType;
  expandedKeys: Set<string>;
  onToggleExpand: (key: string) => void;
}) {
  return (
    <div>
      {/* Day separator */}
      <div className="flex items-center gap-3 py-2">
        <div className="h-px flex-1 bg-border" />
        <span className="text-xs font-medium text-muted-foreground">{day.label}</span>
        <div className="h-px flex-1 bg-border" />
      </div>

      {/* Sessions */}
      <div className="space-y-4">
        {day.sessions.map((session, si) => {
          const filteredEvents =
            activeFilter === "all"
              ? session.events
              : session.events.filter((e) => e.type === activeFilter);

          const clustered = clusterRevisions(filteredEvents);

          if (clustered.length === 0) return null;

          return (
            <div key={si} className="pl-4">
              {/* Session header */}
              <div className="mb-2 flex items-center gap-2 text-xs text-muted-foreground">
                <Play className="h-3 w-3 text-emerald-500" />
                <span className="font-medium">
                  {formatTime(session.startTime)}
                  {session.endTime && ` – ${formatTime(session.endTime)}`}
                </span>
              </div>

              {/* Timeline rail */}
              <div className="relative border-l-2 border-border pl-6 space-y-2">
                {clustered.map((item, ei) => {
                  const key = `${day.date}-${si}-${ei}`;

                  if ("count" in item) {
                    return (
                      <RevisionClusterRow
                        key={key}
                        cluster={item as RevisionCluster}
                      />
                    );
                  }

                  const event = item as TimelineEvent;
                  return (
                    <EventRow
                      key={key}
                      event={event}
                      isExpanded={expandedKeys.has(key)}
                      onToggle={() => onToggleExpand(key)}
                    />
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function EventRow({
  event,
  isExpanded,
  onToggle,
}: {
  event: TimelineEvent;
  isExpanded: boolean;
  onToggle: () => void;
}) {
  if (event.type === "ai_interaction") {
    return (
      <div className="relative">
        {/* Dot */}
        <div className="absolute -left-[31px] top-3 h-2.5 w-2.5 rounded-full bg-violet-400" />
        {/* Card */}
        <div className="rounded-lg border border-violet-200/50 bg-violet-50/30 p-3">
          <button
            onClick={onToggle}
            className="flex w-full items-center justify-between text-left text-sm transition-colors duration-150"
          >
            <div className="flex items-center gap-2">
              <span className="rounded bg-violet-100 px-1.5 py-0.5 text-xs font-medium text-violet-700">
                {String(event.data.mode)}
              </span>
              <span className="truncate text-foreground">
                {String(event.data.prompt).slice(0, 60)}
                {String(event.data.prompt).length > 60 ? "..." : ""}
              </span>
            </div>
            <span className="ml-2 shrink-0 text-xs text-muted-foreground">
              {formatTime(event.timestamp)}
            </span>
          </button>

          {isExpanded && (
            <div className="mt-2 border-t pt-2 text-sm">
              <div className="mb-1">
                <span className="font-medium">Action:</span>{" "}
                <span className={
                  String(event.data.action) === "accepted"
                    ? "text-emerald-700"
                    : String(event.data.action) === "rejected"
                      ? "text-red-600"
                      : "text-amber-600"
                }>
                  {String(event.data.action)}
                </span>
              </div>
              <div className="mb-1">
                <span className="font-medium">Prompt:</span>{" "}
                <span className="break-words text-muted-foreground">
                  {String(event.data.prompt)}
                </span>
              </div>
              <div>
                <span className="font-medium">Response:</span>{" "}
                <span className="break-words text-muted-foreground">
                  {String(event.data.response)}
                </span>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  if (event.type === "paste") {
    return (
      <div className="relative flex items-center gap-3 py-1">
        {/* Dot */}
        <div className="absolute -left-[31px] top-1/2 h-2.5 w-2.5 -translate-y-1/2 rounded-full bg-orange-400" />
        <span className="rounded bg-orange-100 px-1.5 py-0.5 text-xs font-medium text-orange-700">
          paste
        </span>
        <span className="text-sm text-muted-foreground">
          {String(event.data.sourceType)} — {String(event.data.characterCount)} chars
        </span>
        <span className="ml-auto text-xs text-muted-foreground">
          {formatTime(event.timestamp)}
        </span>
      </div>
    );
  }

  // Revision (individual)
  return (
    <div className="relative flex items-center gap-3 py-0.5">
      <div className="absolute -left-[31px] top-1/2 h-2.5 w-2.5 -translate-y-1/2 rounded-full bg-muted-foreground/50" />
      <span className="text-xs text-muted-foreground">
        Revision saved — {String(event.data.trigger)}
      </span>
      <span className="ml-auto text-xs text-muted-foreground">
        {formatTime(event.timestamp)}
      </span>
    </div>
  );
}

function RevisionClusterRow({ cluster }: { cluster: RevisionCluster }) {
  return (
    <div className="relative flex items-center gap-3 py-0.5">
      <div className="absolute -left-[31px] top-1/2 h-2.5 w-2.5 -translate-y-1/2 rounded-full bg-muted-foreground/50" />
      <span className="text-xs text-muted-foreground">
        {cluster.count} revisions over {cluster.durationMinutes}min
      </span>
    </div>
  );
}

import { Extension } from "@tiptap/core";
import { Plugin, PluginKey } from "@tiptap/pm/state";

type ActivationGesture = Pick<MouseEvent, "metaKey" | "ctrlKey">;

export interface EditorInteractionPolicyOptions {
  interactiveSelectors: readonly string[];
  isExplicitActivationGesture: (event: ActivationGesture) => boolean;
}

export const editorInteractionPolicyKey = new PluginKey("editorInteractionPolicy");
export const DEFAULT_INTERACTIVE_SELECTORS = [
  "a[href]",
  "[data-editor-interactive='true']",
] as const;

export function isExplicitActivationGesture(
  event: ActivationGesture
): boolean {
  return event.metaKey || event.ctrlKey;
}

export function buildInteractiveSelector(selectors: readonly string[]): string {
  return selectors
    .map((selector) => selector.trim())
    .filter(Boolean)
    .join(",");
}

function resolveEventTargetElement(target: EventTarget | null): Element | null {
  if (target instanceof Element) return target;
  if (target instanceof Node) return target.parentElement;
  return null;
}

export function shouldSuppressInteractiveClick({
  target,
  interactiveSelector,
  event,
  isEditable,
  isExplicitActivationGesture: allowActivation,
}: {
  target: EventTarget | null;
  interactiveSelector: string;
  event: ActivationGesture;
  isEditable: boolean;
  isExplicitActivationGesture: (event: ActivationGesture) => boolean;
}): boolean {
  if (!isEditable || !interactiveSelector) return false;
  const targetElement = resolveEventTargetElement(target);
  if (!targetElement) return false;

  const interactiveTarget = targetElement.closest(interactiveSelector);
  if (!interactiveTarget) return false;

  return !allowActivation(event);
}

export const EditorInteractionPolicy = Extension.create<EditorInteractionPolicyOptions>(
  {
    name: "editorInteractionPolicy",

    addOptions() {
      return {
        interactiveSelectors: DEFAULT_INTERACTIVE_SELECTORS,
        isExplicitActivationGesture,
      };
    },

    addProseMirrorPlugins() {
      const interactiveSelector = buildInteractiveSelector(
        this.options.interactiveSelectors
      );
      const allowActivation = this.options.isExplicitActivationGesture;

      return [
        new Plugin({
          key: editorInteractionPolicyKey,
          props: {
            handleDOMEvents: {
              click(view, event) {
                if (!(event instanceof MouseEvent)) return false;

                const shouldSuppress = shouldSuppressInteractiveClick({
                  target: event.target,
                  interactiveSelector,
                  event,
                  isEditable: view.editable,
                  isExplicitActivationGesture: allowActivation,
                });

                if (!shouldSuppress) return false;
                event.preventDefault();
                // Let ProseMirror continue processing the click so caret/selection still works.
                return false;
              },
            },
          },
        }),
      ];
    },
  }
);

import { Extension } from "@tiptap/core";
import { Plugin, PluginKey } from "@tiptap/pm/state";
import { DOMParser as ProseMirrorDOMParser } from "@tiptap/pm/model";

export interface PasteHandlerOptions {
  documentId: string;
  onExternalPaste?: (
    content: string,
    characterCount: number,
    sourceId: string
  ) => void;
  recentAIResponses?: string[];
  maxRecentAIResponses?: number;
}

export function classifyPaste(
  clipboardText: string,
  recentAIResponses: string[]
): "external" | "ai_internal" {
  return recentAIResponses.some((r) => r === clipboardText)
    ? "ai_internal"
    : "external";
}

function createSourceId(): string {
  if (globalThis.crypto?.randomUUID) {
    return globalThis.crypto.randomUUID();
  }

  // RFC4122-ish fallback for older runtimes.
  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (char) => {
    const rand = Math.floor(Math.random() * 16);
    const value = char === "x" ? rand : (rand & 0x3) | 0x8;
    return value.toString(16);
  });
}

declare module "@tiptap/core" {
  interface Storage {
    pasteHandler: {
      recentAIResponses: string[];
    };
  }

  interface Commands<ReturnType> {
    pasteHandler: {
      addRecentAIResponse: (text: string) => ReturnType;
      clearRecentAIResponses: () => ReturnType;
    };
  }
}

export const PasteHandler = Extension.create<PasteHandlerOptions>({
  name: "pasteHandler",

  addOptions() {
    return {
      documentId: "",
      onExternalPaste: undefined,
      recentAIResponses: [],
      maxRecentAIResponses: 10,
    };
  },

  addStorage() {
    return {
      recentAIResponses: [] as string[],
    };
  },

  onCreate() {
    const initial = this.options.recentAIResponses ?? [];
    const max = this.options.maxRecentAIResponses ?? 10;

    if (initial.length > 0) {
      this.storage.recentAIResponses = [...initial].slice(0, max);
    }
  },

  addCommands() {
    return {
      addRecentAIResponse:
        (text: string) =>
        () => {
          const trimmed = text.trim();
          if (!trimmed) return false;

          const max = this.options.maxRecentAIResponses ?? 10;
          const next = [
            trimmed,
            ...this.storage.recentAIResponses.filter((r: string) => r !== trimmed),
          ];
          this.storage.recentAIResponses = next.slice(0, max);
          return true;
        },

      clearRecentAIResponses:
        () =>
        () => {
          this.storage.recentAIResponses = [];
          return true;
        },
    };
  },

  addProseMirrorPlugins() {
    const { onExternalPaste } = this.options;
    const storage = this.storage;

    return [
      new Plugin({
        key: new PluginKey("pasteHandler"),
        props: {
          handlePaste(view, event, slice) {
            const clipboardText =
              event.clipboardData?.getData("text/plain") ??
              slice.content.textBetween(0, slice.content.size, "\n\n");
            if (!clipboardText) return false;

            const { schema } = view.state;
            const originMarkType = schema.marks.origin;
            if (!originMarkType) return false;

            const classification = classifyPaste(
              clipboardText,
              storage.recentAIResponses
            );

            const originType =
              classification === "ai_internal" ? "ai" : "external_paste";
            const sourceId = createSourceId();
            const originMark = originMarkType.create({
              type: originType,
              sourceId,
              originalLength: clipboardText.length,
            });

            const { from, to } = view.state.selection;

            // Try to parse HTML to preserve formatting (headings, bold, etc.)
            const clipboardHtml =
              event.clipboardData?.getData("text/html");
            let parsedSlice = slice;
            if (clipboardHtml) {
              const wrapper = document.createElement("div");
              wrapper.innerHTML = clipboardHtml;
              parsedSlice = ProseMirrorDOMParser.fromSchema(schema).parseSlice(
                wrapper
              );
            }

            if (parsedSlice && parsedSlice.content.childCount > 0) {
              // Insert the parsed rich content, then apply origin mark to the range
              const tr = view.state.tr.replaceRange(from, to, parsedSlice);
              const insertEnd = tr.mapping.map(to);
              tr.addMark(from, insertEnd, originMark);
              view.dispatch(tr);
            } else {
              // Fallback: insert plain text with origin mark
              const textNode = schema.text(clipboardText, [originMark]);
              const tr = view.state.tr.replaceWith(from, to, textNode);
              view.dispatch(tr);
            }

            if (classification !== "ai_internal") {
              onExternalPaste?.(clipboardText, clipboardText.length, sourceId);
            }

            return true;
          },
        },
      }),
    ];
  },
});

interface TipTapMark {
  type: string;
  attrs?: Record<string, unknown>;
}

interface TipTapNode {
  type?: string;
  text?: string;
  content?: TipTapNode[];
  marks?: TipTapMark[];
}

interface BadgeStats {
  ai_percentage: number;
  external_paste_percentage: number;
  total_characters: number;
}

interface AiInteractionLike {
  action?: string | null;
  response?: string | null;
}

/** Count characters as Unicode code points, not UTF-16 code units. */
function countChars(text: string): number {
  return Array.from(text).length;
}

function walkTextNodes(
  node: TipTapNode,
  callback: (text: string, marks?: TipTapMark[]) => void
) {
  if (node.text != null) {
    callback(node.text, node.marks);
    return;
  }

  if (node.content) {
    for (const child of node.content) {
      walkTextNodes(child, callback);
    }
  }
}

/**
 * Compute Levenshtein edit distance between two strings.
 * Operates on Unicode code points (not UTF-16 code units) for correct
 * handling of emoji and other characters outside the Basic Multilingual Plane.
 */
export function editDistance(a: string, b: string): number {
  // Spread to get code points instead of UTF-16 code units
  const aChars = [...a];
  const bChars = [...b];
  const m = aChars.length;
  const n = bChars.length;
  if (m === 0) return n;
  if (n === 0) return m;
  if (a === b) return 0;

  // Two-row DP (O(n) space)
  let prev = Array.from({ length: n + 1 }, (_, i) => i);
  let curr = new Array<number>(n + 1);

  for (let i = 1; i <= m; i++) {
    curr[0] = i;
    for (let j = 1; j <= n; j++) {
      const cost = aChars[i - 1] === bChars[j - 1] ? 0 : 1;
      curr[j] = Math.min(prev[j] + 1, curr[j - 1] + 1, prev[j - 1] + cost);
    }
    [prev, curr] = [curr, prev];
  }

  return prev[n];
}

const MIN_RESPONSE_MATCH_CHARS = 20;

function findNonOverlappingMatch(
  text: string,
  pattern: string,
  occupied: boolean[]
): number {
  let fromIndex = 0;
  const maxStart = text.length - pattern.length;
  while (fromIndex <= maxStart) {
    const idx = text.indexOf(pattern, fromIndex);
    if (idx === -1) return -1;

    let overlaps = false;
    for (let i = idx; i < idx + pattern.length; i++) {
      if (occupied[i]) {
        overlaps = true;
        break;
      }
    }

    if (!overlaps) return idx;
    fromIndex = idx + 1;
  }

  return -1;
}

/**
 * Fallback estimator for legacy snapshots that have missing/stripped origin attrs.
 * Counts accepted AI responses that are still present verbatim in final text.
 */
export function estimateRetainedAiCharactersFromAcceptedResponses(
  documentText: string,
  interactions: AiInteractionLike[]
): number {
  if (!documentText || interactions.length === 0) return 0;

  const acceptedResponses = interactions
    .filter(
      (interaction) =>
        interaction.action === "accepted" &&
        typeof interaction.response === "string"
    )
    .map((interaction) => interaction.response?.trim() ?? "")
    .filter((response) => countChars(response) >= MIN_RESPONSE_MATCH_CHARS)
    .sort((a, b) => countChars(b) - countChars(a));

  if (acceptedResponses.length === 0) return 0;

  const occupied = new Array(documentText.length).fill(false);
  let retainedChars = 0;

  for (const response of acceptedResponses) {
    const matchStart = findNonOverlappingMatch(documentText, response, occupied);
    if (matchStart === -1) continue;

    for (let i = matchStart; i < matchStart + response.length; i++) {
      occupied[i] = true;
    }
    retainedChars += countChars(response);
  }

  return retainedChars;
}

export function calculateMetrics(doc: TipTapNode): BadgeStats {
  let aiChars = 0;
  let humanChars = 0;
  let externalPasteChars = 0;

  walkTextNodes(doc, (text, marks) => {
    const originMark = marks?.find((m) => m.type === "origin");
    const length = countChars(text);

    if (!originMark || originMark.attrs?.type === "human") {
      humanChars += length;
    } else if (originMark.attrs?.type === "ai") {
      // Check modification threshold using edit distance
      const originalLength = originMark.attrs?.originalLength as
        | number
        | null;
      const originalText = originMark.attrs?.originalText as string | null;

      if (originalText != null) {
        // Use character-level edit distance for accurate comparison
        const distance = editDistance(originalText, text);
        const maxLen = Math.max(countChars(originalText), length);
        if (maxLen > 0 && distance / maxLen > 0.2) {
          // Modified by >20% edit distance — reclassify as human
          humanChars += length;
        } else {
          aiChars += length;
        }
      } else if (
        originalLength != null &&
        originalLength > 0 &&
        Math.abs(length - originalLength) / Math.max(originalLength, length) > 0.2
      ) {
        // Fallback: length-based check for marks without originalText
        // Uses Math.max(originalLength, length) for consistent normalization
        humanChars += length;
      } else {
        aiChars += length;
      }
    } else if (originMark.attrs?.type === "external_paste") {
      externalPasteChars += length;
    } else {
      humanChars += length;
    }
  });

  const total = aiChars + humanChars + externalPasteChars;
  // Use Math.floor to prevent ai% + external% from exceeding 100%
  const aiPct = total > 0 ? Math.floor((aiChars / total) * 100) : 0;
  const externalPct = total > 0 ? Math.floor((externalPasteChars / total) * 100) : 0;
  return {
    ai_percentage: aiPct,
    external_paste_percentage: externalPct,
    total_characters: total,
  };
}
